INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Soirée SentinElles - Spécial Femmes 🩷', 'ℹ️  Chaque 2ème mercredi du mois, de 18h30 à 21h, le groupe des SentinElles se rassemble pour vivre des moments uniques entre femmes.\n\n💬 C''est l''occasion de plonger dans des thèmes bibliques inspirants, d''échanger librement et de partager des expériences qui nous enrichissent mutuellement. 💫\n\nVien', NULL, '2026-01-13', '18:30', '2026-01-13', '20:00', '', 'month', 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_Sl91fBIgUCFqQadzk1WHr.jpg', 0, 'cieuxouverts.bzh');
INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Célébration 🙌', 'Viens célébrer avec nous le dimanche !\nRejoins-nous pour un moment chaleureux, joyeux, dans l''unité et l''Amour !\n\nAu programme :\n✨ Un accueil convivial autour d’un café offert !\n🎵 Un temps de louange (chants rythmés) et d’adoration (chants plus doux) avec des chants qui disposent le cœur.\n📖 Un mes', '2 rue Jean Monnet, 29600 Morlaix', '2025-02-09', '10:00', '2025-02-09', '12:00', '', 'week', 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_2cbTwdTGHECaGaT3NXhPl.png', 0, 'cieuxouverts.bzh');
INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Réunion de Prières 🙏', 'Unissons nos voix chaque lundi soir !\n\n🙏 Rejoins-nous les lundis, de 20h à 21h15, pour un temps puissant de prières et d’intercessions. \n📣 Ensemble, nous élevons nos voix pour porter devant Dieu les sujets qui touchent nos cœurs et le monde qui nous entoure.\n\nViens participer à ce moment d’impact ', '2 rue Jean Monnet, 29600 Morlaix', '2025-01-20', '20:00', '2025-01-20', '21:15', '', 'week', 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_il3GZztMXu4yQmUArpIYZ.jpg', 0, 'cieuxouverts.bzh');
