INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Repas en commun - Agape 🥘', 'Repas partagé – chaque dernier dimanche du mois !\n\nUn moment chaleureux et convivial où :\n🍲 Chacun apporte un plat, une boisson et/ ou un dessert à partager.\n🍽️ Un grand buffet est installé pour que tout le monde puisse se servir librement.\n🤝 Nous profitons ensemble d’un temps de communion frater', '2 rue Jean Monnet, 29600 Morlaix', '2026-01-25', '12:15', '2026-01-25', '14:15', '', 'month', 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_csUXV8S4gbMwUmPUi50f0.png', 0, 'cieuxouverts.bzh');
