INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Fête de la Résurrection - dans l''unité 🙌', 'Cette année, la date de la fête de Pâques est commune pour les catholiques, protestants et orthodoxes ; c''est pourquoi nous organisons une fête commune ! \nUn évènement dans l''unité à ne pas manquer ! \nUn pot de l''unité sera organisé à l''issue de la célébration.', '2 rue Jean Monnet, 29600 Morlaix', '2025-04-20', '17:00', '2025-04-20', '18:00', '', NULL, 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_bujXFNuaaq9Lm0YMmSpeP.png', 0, 'cieuxouverts.bzh');
