INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Atelier Cuisine', 'Rejoins cet atelier cuisine, qui a pour but : \n- d''accueillir les nouvelles personnes de l''église,\n- d''inviter des connaissances qui parfois sont seules, afin de connecter les uns aux autres\n\nCe temps a pour but de favoriser les échanges autour d''un repas confectionné par chacun, et partagé ensuite ', NULL, '2025-06-14', '18:00', '2025-06-14', '19:00', '', NULL, NULL, 0, 'cieuxouverts.bzh');
INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Fête de l''Eté - 2ème édition', 'Un moment festif, familial et ouvert à tous : que vous soyez membre de l’église, voisin du quartier ou simplement curieux de partager un bon moment en famille ou entre amis.\n🎟️ Entrée gratuite.\nAu programme :\n🎶 Ambiance musicale festive\n🏰 Structures gonflables pour petits et grands\n🎯 Jeux en tou', '2 rue Jean Monnet, 29600 Morlaix', '2025-07-13', '14:00', '2025-07-13', '18:00', '', NULL, NULL, 0, 'cieuxouverts.bzh');
INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Soirée de Prières pour les malades ✨', '✨ 𝗦𝗼𝗶𝗿𝗲́𝗲 𝗱𝗲 𝗽𝗿𝗶𝗲̀𝗿𝗲𝘀 𝗽𝗼𝘂𝗿 𝗹𝗲𝘀 𝗺𝗮𝗹𝗮𝗱𝗲𝘀 ✨\n🙏 Ce vendredi à l’Église Cieux Ouverts, nous nous rassemblerons pour une 𝘀𝗼𝗶𝗿𝗲́𝗲 𝗱𝗲 𝗽𝗿𝗶𝗲̀𝗿𝗲𝘀 𝗲𝗻 𝗳𝗮𝘃𝗲𝘂𝗿 𝗱𝗲𝘀 𝗺𝗮𝗹𝗮𝗱𝗲𝘀.\n👉 𝗨𝗻 𝘁𝗲𝗺𝗽𝘀 𝗽𝗼𝘂𝗿 𝗲𝘅𝗽𝗲́𝗿𝗶𝗺𝗲𝗻𝘁𝗲𝗿 𝗹𝗮 𝗽𝘂𝗶𝘀𝘀𝗮𝗻𝗰𝗲 𝗱', '2 rue Jean Monnet, 29600 Morlaix', '2025-09-26', '20:00', '2025-09-26', '22:00', '', NULL, 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_4F3o5ZSSdNq5UB5Gopiio.jpg', 0, 'cieuxouverts.bzh');
