INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Soirée Témoignages Inédits 💬', 'Dieu s''est révélé à un homme en profonde souffrance. Un évènement bouleversant qui a remis toute sa vie en question. Et qui pourrait bien impacter la vôtre...\nDécouvrez l''histoire de Serge ainsi que d''autres témoignages authentiques et touchants.', '2 rue Jean Monnet, 29600 Morlaix', '2025-11-28', '20:00', '2025-11-28', '22:30', '', NULL, 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_weDJ1jS3qnAdaK8nUqndh.png', 0, 'cieuxouverts.bzh');
INSERT INTO church_events (title, description, location, start_date, start_time, end_date, end_time, color, repeat_period, image_url, rsvp_enabled, source) VALUES ('Ecole du Disciple 👣', 'Tu souhaites cheminer sur les pas de Jésus ? Grandir dans ta foi ? Connaître les dons que Dieu t''a donnés et commencer à servir ? Impacter le monde autour de toi ?\nL''école du disciple, proposée chaque jeudi soir, de 19h30 à 21h00, te permet d''avancer sur ce chemin et de grandir aux côtés d''autres di', '2 rue Jean Monnet, 29600 Morlaix', '2026-01-08', '19:30', '2026-01-08', '21:00', '', 'week', 'https://s3.amazonaws.com/uploadcare.calendar.inffuse.com/HVikDCPSAUqKpWhQoiuT0/CX9wNlTlICvqvTbNpefEi/img_pXhH5AmOeiRuYRafuqR04.jpg', 0, 'cieuxouverts.bzh');
